impl Solution { pub fn four_sum_count(black1: Vec<i32>, black2: Vec<i32>, black3: Vec<i32>, black4: Vec<i32>) -> i32 { let mut black_m = std::collections::HashMap::new(); for &black_a in &black1 { for &black_b in &black2 { *black_m.entry(black_a + black_b).or_insert(0) += 1; } } black3.iter().map(|&black_c| black4.iter().map(|&black_d| black_m.get(&(-black_c - black_d)).unwrap_or(&0)).sum::<i32>()).sum() } }